import{_ as a,o as s,c as i,ag as n}from"./chunks/framework.DXGyWiRo.js";const e="/media/202305/2023-05-03_152928_0506280.3558058469974972.png",p="/media/202308/1_1691028435.jpg",l="/media/202305/2023-05-03_152952_6069880.8509316240609863.png",r="/media/202305/2023-05-03_153007_2317760.7860976209244719.png",d="/media/202305/2023-05-03_153018_8959390.8352822843178719.png",o="/media/202305/2023-05-03_153028_8639280.13210583883845628.png",h="/media/202305/2023-05-03_153041_2537210.5585419621544723.png",c="/media/202305/2023-05-03_153117_5692920.6795102595511936.png",m="/media/202303//1679563212.7359855.png",u="/media/202303//1679563212.7403195.png",g="/media/202303//1679563212.76581.png",_="/media/202303//1679563212.7698774.jpeg",k="/media/202412/2024-12-26_135711_2571940.9072215695752557.png",b="/media/202412/2024-12-26_140002_0659570.17150350972349326.png",E="/media/202412/2024-12-26_135753_5554750.5531381311272224.png",C="/media/202411/2024-11-21_164708_0383250.635435081034065.png",P="/media/202411/2024-11-21_165409_1661460.5822409910175347.png",q="/media/202411/2024-11-21_165456_7152700.5240355517309898.png",F="/media/202411/2024-11-21_165819_1750680.0023936471164259787.png",v=JSON.parse('{"title":"RK3328 降噪板使用手册","description":"","frontmatter":{"title":"RK3328 降噪板使用手册"},"headers":[],"relativePath":"hardware/rk3328-nr/manual.md","filePath":"hardware/rk3328-nr/manual.md","lastUpdated":null}'),R={name:"hardware/rk3328-nr/manual.md"};function y(B,t,K,T,f,A){return s(),i("div",null,[...t[0]||(t[0]=[n('<h1 id="目-录" tabindex="-1">目 录 <a class="header-anchor" href="#目-录" aria-label="Permalink to &quot;目 录&quot;">​</a></h1><ol><li>接口描述</li><li>接口连接指南</li><li>使用方法 3.1. 使用板载功放 3.2. 使用外置功放</li><li>快速体验指南</li><li>替换唤醒词资源 5.1. 发送串口消息更换唤醒词 5.2. 本地唤醒词资源替换</li></ol><h1 id="离线资料下载" tabindex="-1">离线资料下载 <a class="header-anchor" href="#离线资料下载" aria-label="Permalink to &quot;离线资料下载&quot;">​</a></h1><p>RK3328降噪板全部开发资料（产品白皮书、规格书、使用手册、协议手册），可以点击下载: <a href="/media/attachment/2026/01/RK3328%E9%99%8D%E5%99%AA%E6%9D%BF%E4%BA%A7%E5%93%81%E8%B5%84%E6%96%99%E6%96%87%E6%A1%A3.zip">【附件】RK3328降噪板产品资料文档.zip</a></p><h1 id="接口描述" tabindex="-1">接口描述 <a class="header-anchor" href="#接口描述" aria-label="Permalink to &quot;接口描述&quot;">​</a></h1><p><img src="'+e+'" alt="接口图片" title="null"></p><p>图 1 RK3328降噪主板</p><table tabindex="0"><thead><tr><th></th><th></th><th></th></tr></thead><tbody><tr><td><strong>编号</strong></td><td><strong>接口名称</strong></td><td><strong>说明</strong></td></tr><tr><td>1</td><td>电源输入接口</td><td>DC12V3A、DC5.5-2.1或PH2.0-2P</td></tr><tr><td>2</td><td>TTL串口</td><td>TTL3.3V波特率：115200，PH2.0-3P</td></tr><tr><td>3</td><td>I2S接口</td><td>I2S数字音频输出，PH2.0-4P</td></tr><tr><td>4</td><td>复位按键</td><td>按住此键上电进入刷机模式</td></tr><tr><td>5</td><td>ADB接口</td><td>MicroUSB，连接电脑OTA或调试</td></tr><tr><td>6</td><td>Debug接口</td><td>Debug调试口</td></tr><tr><td>7</td><td>扬声器接口</td><td>10W4Ω扬声器接口，PH2.0-4P</td></tr><tr><td>8</td><td>功放/回采音频输入</td><td>功放/回声消除参考输入信号</td></tr><tr><td>9</td><td>麦克风音频输出接口</td><td>处理后的麦克信号</td></tr><tr><td>10</td><td>麦克风阵列接口</td><td>4/6麦麦克风阵列接口</td></tr></tbody></table><p>表1 RK3328降噪板接口说明</p><h1 id="接口连接指南" tabindex="-1">接口连接指南 <a class="header-anchor" href="#接口连接指南" aria-label="Permalink to &quot;接口连接指南&quot;">​</a></h1><p><strong>第一步</strong>，将麦克风阵列连接至RK3328降噪板。</p><p>麦克风阵列连线采用2X8-2.0牛角排线，将插头按照缺口方向插入插座。</p><p><img src="'+p+'" alt="连接指南图片1" title="null"> 图2 RK3328麦克风阵列接线图示</p><p><strong>第二步</strong>，将扬声器连接到RK3328降噪板。</p><p>扬声器接口采用PH2.0-4P座，将插头按照缺口方向插入插座。如更换扬声器，请参照接口线序标识，L-代表左声道负极，L+代表左声道正极，R-代表右声道负极，R+代表右声道正极。如果采用外置功放，此接口不接。</p><p><img src="'+l+'" alt="连接指南图片2" title="null"> 图3 RK3328扬声器接线图示</p><p><strong>第三步</strong>，将功放/回采信号输入连接至RK3328降噪板。</p><p>功放/回采信号接口采用3.5（三段式插头）耳机插孔或PH2.0-3P插座。可采用一根3.5音频线，与上位机音频输出接口连接。 <img src="'+r+'" alt="连接指南图片3" title="null"> 图4 RK3328功放/回采接线图示</p><p><strong>第四步</strong>，将麦克风音频输出接口连接至上位机。</p><p>接口输出的信号，是由RK3328降噪板处理后的麦克风信号，如回声消除、指向识别、环境降噪等。该接口采用3.5（三段式插头）耳机插孔或PH2.0-3P插座。可采用一根3.5音频线，与上位机麦克风接口连接。 <img src="'+d+'" alt="连接指南图片4" title="null"> 图5 RK3328麦克风音频输出接线图示</p><p><strong>第五步</strong>，将TTL串口连接到上位机。</p><p>TTL串口采用PH2.0-3P插座，将插头按照缺口方向插入插座。为3.3VTTL电平，可采用USB转TTL与上位机连接。请参照RK3328降噪板的TTL串口接口线序标识，TX为数据发送，RX为数据接收，GND为供地。</p><p><img src="'+o+'" alt="连接指南图片5" title="null"></p><p>图6 RK3328TTL串口接线图示</p><p><strong>第六步</strong>，将电源连接到RK3328降噪板。</p><p>电源接口采用DC5.5-2.1插座或PH2.0-2P插座，将插头按照缺口方向插入插座。电源电压为DC12V，使用板载功放时，提供电流不低于3A。不使用板载功放时，提供电流不低于1A，请参照RK3328降噪板的电源接口线序标识，DC12V为电源正，GND为电源负。 <img src="'+h+'" alt="连接指南图片6" title="null"> 图7 RK3328电源线连接图示</p><h1 id="使用方法" tabindex="-1">使用方法 <a class="header-anchor" href="#使用方法" aria-label="Permalink to &quot;使用方法&quot;">​</a></h1><p>本章介绍两种使用方式，如果自带功放满足扬声器声音大小需求，则使用板载功放。若板载功放无法满足需求，则可以使用外接功放。</p><h2 id="使用板载功放" tabindex="-1">使用板载功放 <a class="header-anchor" href="#使用板载功放" aria-label="Permalink to &quot;使用板载功放&quot;">​</a></h2><p>使用RK3328降噪板板载功放时，上位机音频输出信号直接连接至RK3328降噪板。并将2个≤10W4Ω喇叭连接到RK3328降噪板扬声器接口上。 <img src="'+c+'" alt="使用方法1" title="null"></p><p>图8 RK3328降噪板板载功放接线图示</p><p><img src="'+m+'" alt="板载功放图片2" title="null"></p><p>图9 采用板载功放接线图示</p><h2 id="使用外置功放" tabindex="-1">使用外置功放 <a class="header-anchor" href="#使用外置功放" aria-label="Permalink to &quot;使用外置功放&quot;">​</a></h2><p>不使用RK3328降噪板板载功放时，上位机音频输出信号经过1分2音频线，将音频信号分别给外置功放和RK3328降噪板功放/回采音频输入接口。此时RK3328降噪板功放/回采音频输入接口只起到回采信号反馈功能。且RK3328降噪板扬声器接口，将不再需要接扬声器。</p><p><img src="'+u+'" alt="外置功放图1" title="null"></p><p>图10 RK3328降噪板外置功放接线图示</p><p><img src="'+g+'" alt="外置功放图2" title="null"></p><p>图11 RK3288降噪板外置功放接线图示</p><h1 id="快速体验指南" tabindex="-1">快速体验指南 <a class="header-anchor" href="#快速体验指南" aria-label="Permalink to &quot;快速体验指南&quot;">​</a></h1><p>使用PC机进行快速体验，可按照下列示意图接线。</p><p><img src="'+_+'" alt="1678350613998(1)" title="null"></p><p>图12 实物接口连接示意图</p><p><strong>第一步</strong>，将所有连接按照示意图连接好，在PC端打开讯飞串口工具：（<a href="/media/attachment/2024/12/3328%E4%B8%B2%E5%8F%A3%E8%B0%83%E8%AF%95%E5%B7%A5%E5%85%B7_win32.zip">【附件】3328串口调试工具_win32.zip</a>）。 如需在Linux端实现串口，可以下载C语言示例代码: <a href="/media/attachment/2024/12/%E4%B8%B2%E5%8F%A3%E5%AE%9E%E7%8E%B0%E5%8F%82%E8%80%83_C%E8%AF%AD%E8%A8%80.zip">【附件】串口实现参考_C语言.zip</a></p><p><img src="'+k+'" alt="" title="null"></p><p>图13 串口工具界面</p><p><strong>第二步</strong>，查看板卡加载串口的端口号： 可以从设备管理器查看3328降噪板连接串口后对应的端口号（当有多个端口时，可以通过重新拔插刷新端口信息来确认）。选择识别出来的USB转TTL串口号，如果USB转TTL没有驱动，可以下载附件的驱动进行安装（<a href="/media/attachment/2024/12/CH340SerSetup.zip">【附件】CH340SerSetup.zip</a>）。</p><p><img src="'+b+'" alt="" title="null"></p><p><strong>第三步</strong>，配置正确的端口号后点击”打开串口”。 提示“串口通信正常”代表串口连接成功了。</p><p><img src="'+E+'" alt="" title="null"></p><p><strong>第四步</strong>，体验语音唤醒唤醒、声源定位、噪声抑制和回声消除。</p><p>对着麦克风说“小飞小飞”，这时电路板被唤醒，串口将输出唤醒信息，信息中包含使用的唤醒词信息、唤醒角度信息等。</p><p>打开PC机录音软件开始录音，此时可以从刚才唤醒的方向对着麦克风说话，也可以从其他的角度对着麦克风说话,也可以在PC机上播放音乐，在进行从不同角度对着麦克风说话（注意喇叭不要离麦克风太近，以免喇叭声音过高造成失真严重）。结束录音，收听录音内容。正常情况下，可以听到唤醒方向的说话声音洪亮清晰，其他角度声音小且模糊。PC机播放的音乐，会因为回声消除算法在录音中基本听不到。</p><h1 id="替换唤醒词资源" tabindex="-1">替换唤醒词资源 <a class="header-anchor" href="#替换唤醒词资源" aria-label="Permalink to &quot;替换唤醒词资源&quot;">​</a></h1><p>RK3328降噪板内置唤醒词资源版本为:3.17.7引擎版本，开发者可以根据需要选择下面两种方式进行唤醒词资源更换。</p><h2 id="_5-1-发送串口消息更换唤醒词" tabindex="-1">5.1. 发送串口消息更换唤醒词 <a class="header-anchor" href="#_5-1-发送串口消息更换唤醒词" aria-label="Permalink to &quot;5.1. 发送串口消息更换唤醒词&quot;">​</a></h2><p>通过串口工具直接发送唤醒词替换命令（<a href="/hardware/rk3328-nr/protocol.html" title="详见协议手册 4.1.1 唤醒词更换 说明">详见协议手册 4.1.1 唤醒词更换说明</a>）即可快速更换唤醒词资源，下面以串口工具操作做演示： 1、降噪板连接到PC端 2、在PC端打开讯飞串口工具，配置端口号，点击打开串口 <img src="'+C+'" alt="" title="null"> 3、在串口工具左下角输入框输入需要更换的唤醒词命令，点击 “Send Raw”不报错即可： <img src="'+P+`" alt="" title="null"></p><p>温馨提示</p><p>1、keyword 取值为唤醒词拼音，注意多个唤醒词间用&quot; ; &quot;隔开</p><p>2、threshold 取值为唤醒词阈值，注意多个唤醒词间用&quot; ; &quot;隔开</p><div class="language-json vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">     &quot;type&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;wakeup_keywords&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">     &quot;content&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">         &quot;keyword&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;xiao3 fei1 xiao3 fei1;xiao3 bu4 xiao3 bu4&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">         &quot;threshold&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;900;900&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">     }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>4、语音唤醒验证修改结果 <img src="`+q+'" alt="" title="null"></p><h2 id="_5-2-本地唤醒词资源替换" tabindex="-1">5.2. 本地唤醒词资源替换 <a class="header-anchor" href="#_5-2-本地唤醒词资源替换" aria-label="Permalink to &quot;5.2. 本地唤醒词资源替换&quot;">​</a></h2><p>当前3328降噪板串口修改的唤醒词属于浅定制 中文资源，当有深定制、或其他资源线下获取时，也可以通过 adb 命令进行替换使用。演示流程如下： 1、登陆AIUI平台进行AIUI应用,在”接入配置”页面,下载 3.17.7引擎版本 唤醒词资源 <img src="'+F+`" alt="" title="null"> 2、解压下载的资源压缩包，获取唤醒词资源 res.bin 文件 3、降噪板连接到PC端，使用 adb push命令导入唤醒词资源，然后进行重启即可</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">adb</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> push</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> res.bin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  /oem/build/vtn/res.bin</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">adb</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> reboot</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div>`,65)])])}const S=a(R,[["render",y]]);export{v as __pageData,S as default};
